      const values = [node?.rawUrl, node?.browseUrl, node?.sourceOrigin, node?.recoveredFromUrl, node?.file?.rawUrl, node?.file?.browseUrl, node?.file?.sourceOrigin, node?.file?.recoveredFromUrl].filter(Boolean).join(' ');
