      const oldSourceSnapshot = old ? {
        repo: old.repo || '',
        ref: old.requestedRef || old.mutableRef || old.sourceRef || old.ref || '',
        rootPaths: Array.isArray(old.rootPaths) ? old.rootPaths.slice() : []
      } : null;
