      const urlRepo = `${parts[0] || ''}/${parts[1] || ''}`.toLowerCase();
      const filePath = parts.slice(3).join('/').toLowerCase();
      return urlRepo === repo && (!rootPaths.length || rootPaths.some((root) => filePath === root || filePath.startsWith(`${root}/`)));
